public class BerekenSocialeBijdragenRszppo extends AbstractBerekenSocialeBijdragen {

    private static final Set<Sleutel<?>> BASIS_RSZ_SLEUTEL = ImmutableSet.of(SleutelCategorie.INSTANCE);
    private static final Set<Sleutel<?>> BIJDRAGE_RSZ_SLEUTEL = ImmutableSet.of(SleutelCategorie.INSTANCE, SleutelPensioenStelsel.INSTANCE);

    private static final MoneyKey[] BASIS_RSZ_KEYS =
            {RekenBasisRszKey.BASIS_RSZ_KEY, RekenBasisRszKey.BASIS_PENSIOENBIJDRAGE_KEY, RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_KEY,
                    RekenBasisRszKey.BASIS_OVERUREN_GECO_KEY, RekenBasisRszKey.BASIS_SOLIDARITEITS_BIJDRAGE_VOERTUIG_KEY,
                    RekenBasisRszKey.BASIS_PENSIOEN_MANDATARIS_KEY, RekenBasisRszKey.BASIS_PENSIOEN_VASTBENOEMDEN_APK_KEY};

    private static final MoneyKey[] BASIS_RSZ_MANDATARIS_KEYS = {RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_KEY, RekenBasisRszKey.BASIS_PENSIOEN_MANDATARIS_KEY};

    private final RegimeRszppoService regimeRszppoService;
    private final RegimeRszppoService regimeApkRszppoService;

    public BerekenSocialeBijdragenRszppo(ConstantManager constantManager, NlpGlobalService globalService) {
        super(constantManager, globalService, new ControleRszKwartaalGrensVrijwilligeBrandweerOld(constantManager, globalService.getRegimeRszppoService()));
        this.regimeRszppoService = globalService.getRegimeRszppoService();
        this.regimeApkRszppoService = globalService.getRegimeApkRszppoService();
    }

    @Override
    public void berekenSocialeBijdragenRszppoPlichtig(RekenContext opdrachtContext, Opdracht opdracht) {
        verdeelBasisRsz(opdrachtContext, opdracht);
        sommeerBasissen(opdrachtContext, opdracht, BASIS_RSZ_KEYS);
        bepaalBijdragen(opdrachtContext, opdracht);
        LoonElementManager manager = opdrachtContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
        RekenTools.deleteKey(manager.getOpdrachtsElementen(opdracht), RekenBasisRszKey.BASIS_BUITENWETTELIJK_PENSIOEN_KEY);
    }

    @Override
    public void berekenSocialeBijdrageMonitoren(RekenContext opdrachtContext, Opdracht opdracht) {
        berekenSocialeBijdragenRszppoPlichtig(opdrachtContext, opdracht);
    }

    @Override
    public void verdeelBasisRsz(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        LoonElementManager manager = opdrachtContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
        RegulManager regulManager = opdrachtContext.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
        Hoedanigheid hoedanigheid = opdracht.getHoedanigheid();
        SleutelSamenNemer aggregatorBasis = new SleutelSamenNemer();
        List<SleutelGegevens> aggregaten = aggregatorBasis.neemSamenVoorSleutel(opdracht, BASIS_RSZ_SLEUTEL);
        for (SleutelGegevens aggregaat : aggregaten) {
            RszppoKategorie categorie = aggregaat.getCategorie();

            Collection<LoonElement> loonElementen = aggregaat.getOpperElementen(manager);
            for (LoonElement loonElement : loonElementen) {
                verdeelBasisRsz(aggregaat.getOpdracht(), rekenTijd, hoedanigheid, categorie, loonElement, regulManager);
            }
        }
    }

    public void verdeelBasisRsz(
            Opdracht opdracht, RekenTijd rekenTijd, Hoedanigheid hoedanigheid, RszppoKategorie categorie, LoonElement loonElement,
            RegulManager regulManager) {
        LocalDate gegevensDatum = rekenTijd.eindDatum;
        AardKodeExtensie loonCode = loonElement.getAardKodeExtensie();
        Money bedrag = loonElement.getPropertyMoney(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY);
        if (bedrag.signum() != 0 && RszTools.heeftBasisRsz(loonCode)) {
            RegimeRszppo regimeRszppo = regimeRszppoService.getByCategorieLoonCodeEnDatum(categorie.getCode(), loonCode.getCode(), gegevensDatum);
            boolean regimeNietGevonden = regimeRszppo == null;
            if (regimeRszppo != null) {
                char regime = regimeRszppo.getRegime();
                switch (regime) {
                    case '1': //basis_niet_onderworpen
                        break;
                    case '2':
                    case 'C':
                        loonElement.putProperty(RekenBasisRszKey.BASIS_RSZ_KEY, bedrag);
                        break;
                    case '3':
                        loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOENBIJDRAGE_KEY, bedrag);
                        break;
                    case 'B':
                        loonElement.putProperty(RekenBasisRszKey.BASIS_RSZ_KEY, bedrag);
                        loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOENBIJDRAGE_KEY, bedrag);
                        break;
                    case '4':
                        loonElement.putProperty(RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_KEY, bedrag);
                        break;
                    case '5':
                        BigDecimal factor =
                                constantManager.getActualConstant(Konstanten.KST_VERHOGING_BASSOC_ARBEIDERS, rekenTijd).getProcentFactor();
                        Money basisGeco = bedrag.multiply(factor);
                        loonElement.putProperty(RekenBasisRszKey.BASIS_OVERUREN_GECO_KEY, basisGeco);
                        break;
                    case 'V':
                        loonElement.putProperty(RekenBasisRszKey.BASIS_SOLIDARITEITS_BIJDRAGE_VOERTUIG_KEY, bedrag);
                        break;
                    default:
                        regimeNietGevonden = true;
                        break;
                }
            }
            if (regimeNietGevonden) {
                AardKodeExtensie aardKodeExtensie = loonElement.getAardKodeExtensie();
                String message = "Nakijken " + (aardKodeExtensie != null ? aardKodeExtensie.getAard() : null) + '-' +
                        (aardKodeExtensie != null ? aardKodeExtensie.getCode() : null) + '-' + (aardKodeExtensie != null ? aardKodeExtensie.getExtensie() : null);
                regulManager.doRegulException(opdracht, Regulkode.RSZREGIME_NIET_GEVONDEN, message);
            }

            RegimeRszppo regimeRszppoApk =
                    regimeApkRszppoService.getByCategorieLoonCodeEnDatum(categorie.getCode(), loonCode.getCode(), gegevensDatum);

            if (regimeRszppoApk != null && regimeRszppoApk.getRegime() == '3') {
                loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOEN_VASTBENOEMDEN_APK_KEY, bedrag);
            }
            if (loonCode.getCode().equals(RszppoPrestatiekode.PK101.getCode()) && hoedanigheid == Hoedanigheid.MANDATARISSEN_NIET_BESCHERMD) {
                loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOEN_MANDATARIS_KEY, bedrag);
            }
        }
        if (loonCode.behoortTotGroep(LooncodeGroepKeyStrings.ERKENT_PREMIE_OF_WG_BIJDR_GROEPSVERZ_KEY)) {
            loonElement.putProperty(RekenBasisRszKey.BASIS_BUITENWETTELIJK_PENSIOEN_KEY, bedrag);
        }
    }

    private void bepaalBijdragen(RekenContext opdrachtContext, Opdracht opdracht) {
        SleutelSamenNemer aggregatorBijdrage = new SleutelSamenNemer();
        List<SleutelGegevens> aggregaten = aggregatorBijdrage.neemSamenVoorSleutel(opdracht, BIJDRAGE_RSZ_SLEUTEL);

        for (MoneyKey bijdrageKey : getBijdragen()) {
            berekenBijdrage(opdrachtContext, RszTools.bijdrageToBasis(bijdrageKey), bijdrageKey, aggregaten);
        }
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        if (heeftPatronaleBijdrageMeerDan10Werknemers(opdracht.getWerkgever(), rekenTijd)) {
            berekenBijdrage(opdrachtContext, RekenBasisRszKey.BASIS_RSZ_KEY, RekenPatronaalRszKey.PATRONALE_BIJDRAGE_MEER_DAN_10WERKNEMERS_KEY, aggregaten);
        }

        berekenBijdrage(opdrachtContext, RekenBasisRszKey.BASIS_TWEEDE_PENSIOENPIJLER_KEY, RekenPatronaalRszKey.PATRONALE_BIJDRAGE_TWEEDE_PENSIOENPIJLER_KEY, aggregaten);
        berekenBijdrage(opdrachtContext, RekenBasisRszKey.BASIS_BONUS_TWEEDE_PENSIOENPIJLER_KEY, RekenPatronaalRszKey.PATRONALE_BIJDRAGE_BONUS_TWEEDE_PENSIOENPIJLER_KEY,
                aggregaten);
    }

    @Override
    public void berekenSocialeBijdragenMandataris(RekenContext opdrachtContext, Opdracht opdracht) {
        verdeelBasisRszMandataris(opdrachtContext, opdracht);
        sommeerBasissen(opdrachtContext, opdracht, BASIS_RSZ_MANDATARIS_KEYS);
        bepaalBijdragenMandataris(opdrachtContext, opdracht);
    }

    public void verdeelBasisRszMandataris(RekenContext opdrachtContext, Opdracht opdracht) {
        LoonElementManager manager = opdrachtContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        for (LoonElement loonElement : loonElementen) {
            verdeelBasisRszMandataris(loonElement);
        }
    }

    @Override
    public void verdeelBasisRszMandataris(LoonElement loonElement) {
        AardKodeExtensie looncode = loonElement.getAardKodeExtensie();
        Money bedrag = loonElement.getPropertyMoney(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY);
        if (bedrag.signum() != 0) {
            if (looncode.behoortTotGroep(LooncodeGroepKeyStrings.MANDATARIS_BAS_DBL_VAKGELD_KEY)) {
                loonElement.putProperty(RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_KEY, bedrag);
            } else {
                if (!looncode.behoortTotGroep(LooncodeGroepKeyStrings.MANDATARIS_ZONDER_BAS_SI_KEY) &&
                        !looncode.behoortTotGroep(LooncodeGroepKeyStrings.ZONDER_BAS_SI_KEY)) {
                    loonElement.putProperty(RekenBasisRszKey.BASIS_PENSIOEN_MANDATARIS_KEY, bedrag);
                }
            }
        }
    }

    public void bepaalBijdragenMandataris(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        BigDecimal percentageBijdragePensioenMandataris =
                constantManager.getActualConstant(Konstanten.KST_PCT_PENS_INH_MAND, rekenTijd).getProcentFactor();
        berekenBijdrage(opdrachtContext, RekenBasisRszKey.BASIS_PENSIOEN_MANDATARIS_KEY, percentageBijdragePensioenMandataris,
                RekenRszKey.BIJDRAGE_PENSIOEN_MANDATARIS_KEY,
                opdracht);

        BigDecimal percentageBijdrageDubbelVakantiegeldMandataris =
                constantManager.getActualConstant(Konstanten.KST_PCT_DVAK_INH_MAND, rekenTijd).getProcentFactor();
        berekenBijdrage(opdrachtContext, RekenBasisRszKey.BASIS_DUBBEL_VAKANTIEGELD_KEY, percentageBijdrageDubbelVakantiegeldMandataris,
                RekenRszKey.BIJDRAGE_DUBBEL_VAKANTIEGELD_KEY, opdracht);

        BigDecimal percentagePatronaleBijdragePensioenMandataris =
                constantManager.getActualConstant(Konstanten.KST_PCT_PENS_BIJDR_MAND, rekenTijd).getProcentFactor();
        berekenBijdrage(opdrachtContext, RekenBasisRszKey.BASIS_PENSIOEN_MANDATARIS_KEY, percentagePatronaleBijdragePensioenMandataris,
                RekenPatronaalRszKey.PATRONALE_BIJDRAGE_PENSIOEN_MANDATARIS_KEY, opdracht);
    }

    @Override
    public void berekenSocialeBijdrageVoertuig(RekenContext opdrachtContext, Opdracht opdracht, RegulManager regulManager) {
        //Er was geen speciale methode voor het berekenen van SocialeBijdrageVoertuig in het rszpo tijdperk
    }

}
